    WHEN '/dashboard/ehb/absensi' THEN 'Absensi Peserta'
    WHEN '/dashboard/ehb/absensi-pengawas' THEN 'Absensi Pengawas'
    ELSE title
  END,
  urutan = CASE href
    WHEN '/dashboard' THEN 0

