SET
  sakit_apa = CASE
    WHEN keterangan IN ('BELI_SURAT', 'TIDAK_BELI') THEN NULL
    ELSE keterangan
  END,
  beli_surat = CASE WHEN keterangan = 'BELI_SURAT' THEN 1 ELSE 0 END
WHERE sakit_apa IS NULL;

